<template>
    <div class="extended-track-preview">
        <Collage :items="artists"
            :default="defaultProfileImage"
            :highQuality="true"
            :vinyl="!!state"
            :playing="state === 'playing'"
            borderRadius="160px"
        />

        <div class="track-preview-box">
            <TrackPreview
                :item="props.item"
                :light="props.light"
                :showKebab="props.showKebab"
                :externalPlay="props.externalPlay"
                :skeleton="props.skeleton"
                :playable="props.playable"
                :showLike="true"
                @play="emit('play', $event)"
                @color="emit('color', $event)"
                @change="emit('change', $event)"
            />
        </div>
    </div>
</template>

<script setup>
    import { computed } from 'vue';
    import TrackPreview from '🔗/components/ui/TrackPreview.vue';
    import Collage from '🔗/components/ui/Collage.vue';
    import api from '🔗/api';
    import stores from '@/stores';

    const player = stores.player();

    const emit = defineEmits(['change', 'play', 'color']);

    const props = defineProps({
        item: { type: Object, default: () => ({}) },
        skeleton: { type: Boolean, default: false },
        playable: { type: Boolean, default: true },
        light: { type: Boolean, default: false },
        showKebab: { type: Boolean, default: false },
        externalPlay: { type: Boolean, default: false }
    });

    const state = computed(() => {
        if (!player.panes.default || player.panes.default._item?.id !== props.item?.id) {
            return;
        }

        return player.panes.default._state;
    });

    const artists = computed(() => {
        if (!props.item?.contributors?.length) {
            return [];
        }

        return props.item.contributors.filter(item => item.role === 'PRIMARY' && item.state === 'CONFIRMED').map(item => item.artist.profileImage);
    });

    const defaultProfileImage = computed(() => {
        return api.artists().defaultProfileImage;
    });
</script>

<style lang="scss" scoped>
    .extended-track-preview {
        display: flex;
        flex-direction: column;
        align-items: center;
        overflow: hidden;
        .collage {
            width: 320px;
            margin: 5px auto;
        }

        .track-preview-box {
            padding: 8px;
            width: 280px;
            border-radius: 12px;
            background: var(--gray-90);
            margin-top: -66px;
            z-index: 1;
        }
    }
</style>