<template>
    <div
        class="collage"
        :class="{
            vinyl: props.vinyl
        }"
        v-if="itemsToRender.length"
        :style="{
            '--gap': props.gap,
            '--border-radius': props.borderRadius,
            transform: `rotate(${currentRotation}deg)`
        }"
    >
        <template v-for="(item, index) in itemsToRender" :key="index">
            <Img
                class="collage-item"
                :class="[
                    `layout-${itemsToRender.length}-${index + 1}`,
                    cornerClass(itemsToRender.length, index + 1),
                    animationClass
                ]"
                :skeleton="true"
                :preview="props.highQuality ? (item?.crop || props.default?.crop) : (item?.resized || props.default?.resized)"
                :original="item?.original || props.default?.original"
                :alt="item?.alt || ''"
            />
        </template>
    </div>
</template>

<script setup>
    import { ref, watch, onBeforeUnmount, computed } from 'vue';
    import Img from '🔗/components/ui/Img.vue';

    const props = defineProps({
        items: { type: Array, default: () => [] },
        default: { type: [Object, null], default: null },
        gap: { type: String, default: '2px' },
        highQuality: { type: Boolean, default: false },
        borderRadius: { type: String, default: '8px' },
        maxPreviewCount: { type: [Number, null], default: 8 },
        animationType: {
            type: String,
            default: 'none',
            validator: val => ['none', 'breath', 'float', 'tilt', 'pulse'].includes(val)
        },
        playing: { type: Boolean, default: false },
        vinyl: { type: Boolean, default: false }
    });

    const currentRotation = ref(0);
    let animationFrameId = null;

    // Функция для обновления угла вращения
    const updateRotation = (timestamp) => {
        const rotationSpeed = 360 / 24000; // 360deg за 24 сек
        currentRotation.value += rotationSpeed * (16); // приближенно 60fps
        currentRotation.value %= 360;
        animationFrameId = requestAnimationFrame(updateRotation);
    }

    watch(
        () => props.playing,
        (val) => {
            if (val) {
                // Запуск вращения
                animationFrameId = requestAnimationFrame(updateRotation);
            } else {
                // Остановка вращения
                if (animationFrameId) {
                    cancelAnimationFrame(animationFrameId);
                    animationFrameId = null;
                }
            }
        },
        { immediate: true }
    );

    watch(
        () => props.vinyl,
        (val) => {
            if (!props.vinyl) {
                currentRotation.value = 0;
            }
        },
        { immediate: true }
    );

    const itemsToRender = computed(() => {
        return props.maxPreviewCount !== null
            ? props.items.slice(0, props.maxPreviewCount)
            : props.items;
    });

    const animationClass = computed(() => {
        return props.animationType !== 'none' ? `img-anim-${props.animationType}` : '';
    });

    function cornerClass(count, pos) {
        const cornersMap = {
            1: { 1: 'corner-all' },
            2: { 1: 'corner-left', 2: 'corner-right' },
            3: { 1: 'corner-top-left', 2: 'corner-top-right', 3: 'corner-bottom' },
            4: {
                1: 'corner-top-left',
                2: 'corner-top-right',
                3: 'corner-bottom-left',
                4: 'corner-bottom-right'
            },
            5: { 1: 'corner-top-left', 2: 'corner-top-right', 5: 'corner-bottom' },
            6: { 1: 'corner-top-left', 3: 'corner-top-right', 4: 'corner-bottom-left', 6: 'corner-bottom-right' },
            7: { 1: 'corner-top-left', 3: 'corner-top-right', 4: 'corner-bottom-left', 6: 'corner-bottom-right' },
            8: { 1: 'corner-top-left', 4: 'corner-top-right', 5: 'corner-bottom-left', 8: 'corner-bottom-right' }
        };

        return (cornersMap[count] && cornersMap[count][pos]) || '';
    }

    onBeforeUnmount(() => {
        if (animationFrameId) {
            cancelAnimationFrame(animationFrameId);
        }
    });
</script>

<style lang="scss" scoped>
    .collage {
        position: relative;
        width: 100%;
        aspect-ratio: 1 / 1;
    }

    .collage-item {
        position: absolute;
        object-fit: cover;
        overflow: hidden;
        border-radius: 0;
        will-change: transform, opacity;
    }

    /* Скругления */
    .corner-all {
        border-radius: var(--border-radius);
    }
    .corner-top-left {
        border-top-left-radius: var(--border-radius);
    }
    .corner-top-right {
        border-top-right-radius: var(--border-radius);
    }
    .corner-bottom-left {
        border-bottom-left-radius: var(--border-radius);
    }
    .corner-bottom-right {
        border-bottom-right-radius: var(--border-radius);
    }
    .corner-left {
        border-top-left-radius: var(--border-radius);
        border-bottom-left-radius: var(--border-radius);
    }
    .corner-right {
        border-top-right-radius: var(--border-radius);
        border-bottom-right-radius: var(--border-radius);
    }
    .corner-bottom {
        border-bottom-left-radius: var(--border-radius);
        border-bottom-right-radius: var(--border-radius);
    }

    /* Анимации для изображений */
    @keyframes breath {
        0%, 100% { transform: scale(1); }
        50% { transform: scale(1.02); }
    }

    @keyframes float {
        0%, 100% { transform: translateY(1px); }
        50% { transform: translateY(-1px); }
    }

    @keyframes tilt {
        0%, 100% { transform: rotate(-2deg); }
        50% { transform: rotate(2deg); }
    }

    @keyframes pulse {
        0%, 100% { opacity: 1; }
        50% { opacity: 0.96; }
    }

    .img-anim-breath {
        animation: breath 6s ease-in-out infinite;
    }

    .img-anim-float {
        animation: float 5s ease-in-out infinite;
    }

    .img-anim-tilt {
        animation: tilt 7s ease-in-out infinite;
    }

    .img-anim-pulse {
        animation: pulse 4s ease-in-out infinite;
    }

    /* Layout generator */
    @mixin generate-collage-layout($count, $positions, $gap) {
        @for $i from 1 through length($positions) {
            $pos: nth($positions, $i);
            $top: nth($pos, 1);
            $left: nth($pos, 2);
            $width: nth($pos, 3);
            $height: nth($pos, 4);

            .layout-#{$count}-#{$i} {
                top: calc(#{$top} + #{$gap} / 2);
                left: calc(#{$left} + #{$gap} / 2);
                width: calc(#{$width} - #{$gap});
                height: calc(#{$height} - #{$gap});
            }
        }
    }

    @include generate-collage-layout(1, (
        (0%, 0%, 100%, 100%),
    ), var(--gap));

    @include generate-collage-layout(2, (
        (0%, 0%, 50%, 100%),
        (0%, 50%, 50%, 100%)
    ), var(--gap));

    @include generate-collage-layout(3, (
        (0%, 0%, 50%, 50%),
        (0%, 50%, 50%, 50%),
        (50%, 0%, 100%, 50%)
    ), var(--gap));

    @include generate-collage-layout(4, (
        (0%, 0%, 50%, 50%),
        (0%, 50%, 50%, 50%),
        (50%, 0%, 50%, 50%),
        (50%, 50%, 50%, 50%)
    ), var(--gap));

    @include generate-collage-layout(5, (
        (0%, 0%, 50%, 50%),
        (0%, 50%, 50%, 50%),
        (50%, 0%, 50%, 50%),
        (50%, 50%, 50%, 50%),
        (33.33%, 33.33%, 33.33%, 33.33%)
    ), var(--gap));

    @include generate-collage-layout(6, (
        (0%, 0%, 33.33%, 50%),
        (0%, 33.33%, 33.33%, 50%),
        (0%, 66.66%, 33.33%, 50%),
        (50%, 0%, 33.33%, 50%),
        (50%, 33.33%, 33.33%, 50%),
        (50%, 66.66%, 33.33%, 50%)
    ), var(--gap));

    @include generate-collage-layout(7, (
        (0%, 0%, 33.33%, 33.33%),
        (0%, 33.33%, 33.33%, 33.33%),
        (0%, 66.66%, 33.33%, 33.33%),
        (33.33%, 0%, 33.33%, 33.33%),
        (33.33%, 33.33%, 33.33%, 33.33%),
        (33.33%, 66.66%, 33.33%, 33.33%),
        (66.66%, 33.33%, 33.33%, 33.33%)
    ), var(--gap));

    @include generate-collage-layout(8, (
        (0%, 0%, 25%, 50%),
        (0%, 25%, 25%, 50%),
        (0%, 50%, 25%, 50%),
        (0%, 75%, 25%, 50%),
        (50%, 0%, 25%, 50%),
        (50%, 25%, 25%, 50%),
        (50%, 50%, 25%, 50%),
        (50%, 75%, 25%, 50%)
    ), var(--gap));


    @keyframes fadeIn {
        to {
            opacity: 1; /* конечное состояние */
        }
    }

    @keyframes fadeVinylIn {
        to {
            scale: 0.7;
        }
    }

    .collage {
        &.vinyl {
            border-radius: 50%;
            scale: 1;
            animation: fadeVinylIn .4s ease forwards;

            &:before {
                box-shadow: 0px 0px 5px var(--dark-20);
                content: '';
                position: absolute;
                inset: -22%;
                opacity: 0;
                animation: fadeIn .4s ease forwards;
                overflow: hidden;
                border-radius: 50%;
                background:radial-gradient(
                        circle at center,
                        var(--white-500) 0%,
                        var(--white-500) 50%,
                        var(--gray-10) 51%,
                        var(--white-500) 53%,
                        var(--gray-10) 55%,
                        var(--white-500) 57%,
                        var(--white-500) 100%
                    ),
                    repeating-radial-gradient(
                        circle at center,
                        var(--dark-5) 0px,
                        var(--dark-5) 1px,
                        transparent 2px,
                        transparent 6px
                    );
                background-blend-mode: overlay;
            }
            position: relative;

            &:after {
                content: "";
                position: absolute;
                inset: 48%;
                background: var(--white-500);
                border-radius: 50%;
                opacity: 0;
                animation: fadeIn 1s ease forwards;
                animation-delay: 0.5s;
            }

            // .collage-item {
            //     position: absolute;
            //     inset: 15%;
            //     width: 70%;
            //     height: 70%;
            //     object-fit: cover;
            //     border-radius: 50%;
            //     opacity: 0;
            //     animation: fadeIn .8s ease forwards;
            //     animation-delay: 0s;
            // }
        }
    }
</style>
