<template>
    <Block code="tracks"
        v-bind="props"
        ref="block"
        @change="onClick"
        :id="player.panes?.default?._item?.id"
        :sliderPreudo="props.subtype === 'extended'"
        :sliderProps="props.subtype === 'extended' ? {
            itemWidth: '342px',
            colAlign: 'center',
            colGap: '8px',
            rowGap: '8px'
        } : {
            itemWidth: '90%',
            colAlign: 'start',
            colGap: '8px',
            rowGap: '8px'
        }"
        style="--slider-pseudo-width: calc(50% - 179px)"
    >
        <template #list-item="{ item }">
            <ExtendedTrackPreview v-if="props.subtype === 'extended'"
                :item="item"
                :light="true"
                :externalPlay="true"
                :showKebab="props.showKebab"
                @play="onPlaying(item)"
            />

            <TrackPreview v-else
                :item="item"
                :light="true"
                :externalPlay="true"
                :showKebab="props.showKebab"
                @play="onPlaying(item)"
            />
        </template>

        <template #list-skeleton>
            <ExtendedTrackPreview v-if="props.subtype === 'extended'"
                :skeleton="true"
                :playable="false"
                :light="true"
            />

            <TrackPreview v-else
                :skeleton="true"
                :playable="false"
                :light="true"
            />
        </template>

        <template #row-item="{ item }">
            <ExtendedTrackPreview v-if="props.subtype === 'extended'"
                :item="item"
                :light="true"
                :showKebab="props.showKebab"
                :externalPlay="true"
                @play="onPlaying(item)"
            />

            <TrackPreview v-else
                :item="item"
                :light="true"
                :showKebab="props.showKebab"
                :externalPlay="true"
                @play="onPlaying(item)"
            />
        </template>

        <template #row-skeleton>
            <ExtendedTrackPreview v-if="props.subtype === 'extended'"
                :skeleton="true"
                :light="true"
            />

            <TrackPreview v-else
                :skeleton="true"
                :light="true"
            />
        </template>
    </Block>
</template>

<script setup>
    import Block from '🔗/components/blocks/Block.vue';

    import { ref } from 'vue';
    import TrackPreview from '🔗/components/ui/TrackPreview.vue';
    import ExtendedTrackPreview from '🔗/components/ui/ExtendedTrackPreview.vue';
    import stores from '@/stores';

    const emit = defineEmits(['change']);

    const nav = stores.nav();
    const player = stores.player();

    const block = ref(null);

    const props = defineProps({
        empty: { type: Object, default: () => ({}) },
        items: { type: Array, default: () => ([]) },
        title: { type: [Object, String, null], default: null },
        params: { type: Object, default: () => ({}) },
        options: { type: Object, default: () => ({}) },
        sort: { type: [Object, null], default: () => ({
            code: 'name',
            direction: 'asc'
        }) },
        loadMore: { type: Boolean, default: true },
        showKebab: { type: Boolean, default: false },
        skeleton: { type: Boolean, default: true },
        skeletonCount: { type: Number, default: 6 },
        itemsInCol: { type: Number, default: 3 },
        take: { type: Number, default: 30 },
        handler: { type: [String, null], default: () => null },
        type: { type: String, default: 'list' },
        source: { type: [Object, null], default: () => ({ store: 'tracks', fnName: 'list' }) },
        buttons: { type: Array, default: () => ([]) },
        subtype: { type: [String, null], default: null },
        getById: { type: [String, null], default: null }
    });

    const reload = () => {
        if (block?.value?.reload) {
            block.value.reload();
        }
    };

    const onClick = (item) => {
        emit('change', item);

        // if (props.handler === 'track' && item?.id) {
        //     nav.open('track', { id: item?.id });
        // }
    }

    const onPlaying = async (item) => {
        const { items, total } = block.value.getState();

        await player.tracks({
            params: props.params,
            sort: props.sort,
            options: {
                ...props.options,
                source: props.source,
                items: [...items],
                total,
                getById: props.getById
            },
            loadMore: (!props.options?.type && props.loadMore) || ['artist', 'playlist'].indexOf(props.options?.type) !== -1 
        });

        await player.track(item);
        player.play();
    }

    defineExpose({
        reload
    });

</script>